```cpp
#include <iostream>

class Singleton {
public:
    static int& get() {
        return value_;
    }

private:
    static int value_;
};

int Singleton::value_ = 0;

int main() {
    std::cout << Singleton::get() << std::endl; // imprime 0
    Singleton::get() = 10;
    std::cout << Singleton::get() << std::endl; // imprime 10
